+function changedAt(state: any, previous: any, path: string): boolean {
+  const parts = path.split('.')
+  const read = (value: any) => parts.reduce((current, part) => {
+    if (current == null) return undefined
+    if (part.startsWith('map:')) return current instanceof Map ? current.get(part.slice(4)) : undefined
+    if (part.startsWith('set:')) return current instanceof Set ? current.has(part.slice(4)) : undefined
+    return current[part]
+  }, value)
